    .style-fortune .card-content-wrapper {
        background: #faeeee; /* 使用与小票相似的米黄底色 */
        border: 1px solid #dcc6c5;
        border-radius: 8px;
        box-shadow: 2px 2px 10px rgba(0, 0, 0, 0.1), inset 0 0 15px rgba(230, 220, 200, 0.3);
