    .style-fortune .calendar-top-rings span {
        width: 12px;
        height: 12px;
        border-radius: 50%;
        background: #fdf4f0;
        border: 1px solid #c8bba8;
        box-shadow: inset 1px 1px 3px rgba(0,0,0,0.15);
