                    <path
                        d="M9 10a5 5 0 0 1 5 5v3.5a3.5 3.5 0 0 1-6.84 1.045Q6.52 17.48 4.46 16.84A3.5 3.5 0 0 1 5.5 10Z" />
                </svg>
            </div>

            <div class="card-content">
                <div class="corner-info corner-text">Choose · Sth.</div>
                <div class="content-wrapper">
