            --novel-text: #e0e5f0;
            --novel-card-bg: rgba(255, 255, 255, 0.08); /* 提亮卡片背景 */
            --novel-border: rgba(173, 216, 230, 0.25);  /* 冰蓝边框 */
            --novel-tag-bg: rgba(0, 0, 0, 0.2);
