            color: #e0e5f0 !important;
        }

        /* 黑夜模式下的标题颜色强制变亮 */
        .novel-header-container.night-mode .novel-title {
            color: #fff !important;
            text-shadow: 0 0 10px rgba(173, 216, 230, 0.5);
        }

        /* 开关按钮 */
        .theme-toggle-btn {
            position: absolute;
            top: 10px;
            right: 15px;
            background: transparent;
