      // --- 世界书快捷菜单事件处理 ---
      $body.on(
        "change.tagger",
        `#${QUICK_MENU_ID} .quick-wb-toggle`,
        async function () {
          const $chk = window.parent.$(this);
          const wbName = $chk.attr("data-wb-name");
          const enabled = $chk.is(":checked");
          await toggleWorldbookGlobal(wbName, enabled);
